Definition typeSchemeToFType : forall (_ : TypeScheme) , Type_ := fun (ts : TypeScheme) => let vars := (fun r_ => (typeScheme_variables) (r_)) (ts) in let body := (fun r_ => (typeScheme_type) (r_)) (ts) in (((lists.foldl) (fun (t : Type_) => fun (v : Name) => (Type__Forall) ((Build_ForallType) (v) (t)))) (body)) ((lists.reverse) (vars)).
Definition fTypeToTypeScheme : forall (_ : Type_) , TypeScheme := fun (typ : Type_) => let stripAnnotations := (hydra_fix) (fun stripAnnotations => fun (t : Type_) => (fun x_ => match x_ with
| Type__Annotated v_ => (fun (at_ : AnnotatedType) => (stripAnnotations) ((fun r_ => (annotatedType_body) (r_)) (at_))) (v_)
| _ => t
end) (t)) in let gatherForall := (hydra_fix) (fun gatherForall => fun (vars : (list) (Name)) => fun (typ2 : Type_) => (fun x_ => match x_ with
| Type__Forall v_ => (fun (ft : ForallType) => ((gatherForall) (((lists.cons) ((fun r_ => (forallType_parameter) (r_)) (ft))) (vars))) ((fun r_ => (forallType_body) (r_)) (ft))) (v_)
| _ => (Build_TypeScheme) ((lists.reverse) (vars)) (typ2) (None)
end) ((stripAnnotations) (typ2))) in ((gatherForall) (nil)) (typ).
Definition extendGraphWithBindings : forall (_ : (list) (Binding)) , forall (_ : hydra.graph.Graph) , hydra.graph.Graph := fun (bindings : (list) (Binding)) => fun (g : hydra.graph.Graph) => let newTypes := (maps.fromList) ((maybes.cat) (((lists.map) (fun (b : Binding) => ((maybes.map) (fun (ts : TypeScheme) => (pair) ((fun r_ => (binding_name) (r_)) (b)) (ts))) ((fun r_ => (binding_type) (r_)) (b)))) (bindings))) in let newTerms := (maps.fromList) (((lists.map) (fun (b : Binding) => (pair) ((fun r_ => (binding_name) (r_)) (b)) ((fun r_ => (binding_term) (r_)) (b)))) (bindings)) in (Build_Graph) (((maps.union) (newTerms)) ((fun r_ => (graph_boundTerms) (r_)) (g))) (((maps.union) (newTypes)) ((fun r_ => (graph_boundTypes) (r_)) (g))) ((fun r_ => (graph_classConstraints) (r_)) (g)) ((fun r_ => (graph_lambdaVariables) (r_)) (g)) ((fun r_ => (graph_metadata) (r_)) (g)) ((fun r_ => (graph_primitives) (r_)) (g)) ((fun r_ => (graph_schemaTypes) (r_)) (g)) ((fun r_ => (graph_typeVariables) (r_)) (g)).
Definition extendGraphForTypeLambda : forall (_ : hydra.graph.Graph) , forall (_ : TypeLambda) , hydra.graph.Graph := fun (g : hydra.graph.Graph) => fun (tlam : TypeLambda) => let name := (fun r_ => (typeLambda_parameter) (r_)) (tlam) in (Build_Graph) ((fun r_ => (graph_boundTerms) (r_)) (g)) ((fun r_ => (graph_boundTypes) (r_)) (g)) ((fun r_ => (graph_classConstraints) (r_)) (g)) ((fun r_ => (graph_lambdaVariables) (r_)) (g)) ((fun r_ => (graph_metadata) (r_)) (g)) ((fun r_ => (graph_primitives) (r_)) (g)) ((fun r_ => (graph_schemaTypes) (r_)) (g)) (((sets.insert) (name)) ((fun r_ => (graph_typeVariables) (r_)) (g))).
Definition extendGraphForLet : forall (_ : forall (_ : hydra.graph.Graph) , forall (_ : Binding) , (option) (Term)) , forall (_ : hydra.graph.Graph) , forall (_ : Let) , hydra.graph.Graph := fun (forBinding : forall (_ : hydra.graph.Graph) , forall (_ : Binding) , (option) (Term)) => fun (g : hydra.graph.Graph) => fun (letrec : Let) => let bindings := (fun r_ => (let_bindings) (r_)) (letrec) in let g2 := ((extendGraphWithBindings) (bindings)) (g) in (Build_Graph) (((maps.union) ((maps.fromList) (((lists.map) (fun (b : Binding) => (pair) ((fun r_ => (binding_name) (r_)) (b)) ((fun r_ => (binding_term) (r_)) (b)))) (bindings)))) ((fun r_ => (graph_boundTerms) (r_)) (g))) (((maps.union) ((maps.fromList) ((maybes.cat) (((lists.map) (fun (b : Binding) => ((maybes.map) (fun (ts : TypeScheme) => (pair) ((fun r_ => (binding_name) (r_)) (b)) (ts))) ((fun r_ => (binding_type) (r_)) (b)))) (bindings))))) ((fun r_ => (graph_boundTypes) (r_)) (g))) ((fun r_ => (graph_classConstraints) (r_)) (g)) ((((lists.foldl) (fun (s : (list) (Name)) => fun (b : Binding) => ((sets.delete) ((fun r_ => (binding_name) (r_)) (b))) (s))) ((fun r_ => (graph_lambdaVariables) (r_)) (g))) (bindings)) ((fun r_ => (graph_metadata) (r_)) ((((lists.foldl) (fun (gAcc : hydra.graph.Graph) => fun (b : Binding) => let m := (fun r_ => (graph_metadata) (r_)) (gAcc) in let newMeta := (((maybes.maybe) (((maps.delete) ((fun r_ => (binding_name) (r_)) (b))) (m))) (fun (t : Term) => (((maps.insert) ((fun r_ => (binding_name) (r_)) (b))) (t)) (m))) (((forBinding) (gAcc)) (b)) in (Build_Graph) ((fun r_ => (graph_boundTerms) (r_)) (gAcc)) ((fun r_ => (graph_boundTypes) (r_)) (gAcc)) ((fun r_ => (graph_classConstraints) (r_)) (gAcc)) ((fun r_ => (graph_lambdaVariables) (r_)) (gAcc)) (newMeta) ((fun r_ => (graph_primitives) (r_)) (gAcc)) ((fun r_ => (graph_schemaTypes) (r_)) (gAcc)) ((fun r_ => (graph_typeVariables) (r_)) (gAcc)))) (g2)) (bindings))) ((fun r_ => (graph_primitives) (r_)) (g)) ((fun r_ => (graph_schemaTypes) (r_)) (g)) ((fun r_ => (graph_typeVariables) (r_)) (g)).
Definition extendGraphForLambda : forall (_ : hydra.graph.Graph) , forall (_ : Lambda) , hydra.graph.Graph := fun (g : hydra.graph.Graph) => fun (lam : Lambda) => let var := (fun r_ => (lambda_parameter) (r_)) (lam) in (Build_Graph) ((fun r_ => (graph_boundTerms) (r_)) (g)) ((((maybes.maybe) ((fun r_ => (graph_boundTypes) (r_)) (g))) (fun (dom : Type_) => (((maps.insert) (var)) ((fTypeToTypeScheme) (dom))) ((fun r_ => (graph_boundTypes) (r_)) (g)))) ((fun r_ => (lambda_domain) (r_)) (lam))) ((fun r_ => (graph_classConstraints) (r_)) (g)) (((sets.insert) (var)) ((fun r_ => (graph_lambdaVariables) (r_)) (g))) (((maps.delete) (var)) ((fun r_ => (graph_metadata) (r_)) (g))) ((fun r_ => (graph_primitives) (r_)) (g)) ((fun r_ => (graph_schemaTypes) (r_)) (g)) ((fun r_ => (graph_typeVariables) (r_)) (g)).

